        "jsx"  to CommentStyle("//", "/*", "*/"),
        "ts"   to CommentStyle("//", "/*", "*/"),
        "tsx"  to CommentStyle("//", "/*", "*/"),
        "mjs"  to CommentStyle("//", "/*", "*/"),
        "css"  to CommentStyle(null, "/*", "*/"),
        "scss" to CommentStyle("//", "/*", "*/"),
        "less" to CommentStyle("//", "/*", "*/"),
        // Systems languages
