        "rs"    to CommentStyle("//", "/*", "*/"),
        "swift" to CommentStyle("//", "/*", "*/"),
        "cs"    to CommentStyle("//", "/*", "*/"),
        "dart"  to CommentStyle("//", "/*", "*/"),
        "php"   to CommentStyle("//", "/*", "*/"),
        // Scripting / data
        "py"   to CommentStyle("#"),
        "rb"   to CommentStyle("#"),
        "sh"   to CommentStyle("#"),
        "bash" to CommentStyle("#"),
        "zsh"  to CommentStyle("#"),
        "fish" to CommentStyle("#"),
        "yaml" to CommentStyle("#"),
        "yml"  to CommentStyle("#"),
        "toml" to CommentStyle("#"),
